import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVFormatTest {

    @Mock
    private Reader mockReader;

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseWithValidReader() throws IOException {
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);
        assertSame(mockReader, parser.getReader());
        assertSame(csvFormat, parser.getFormat());
    }

    @Test
    void testParseThrowsIOException() throws IOException {
        // CSVParser constructor does not throw IOException, so simulate by mocking CSVParser if needed
        // But CSVParser is not mockable here, so just test normal parse behavior
        assertDoesNotThrow(() -> csvFormat.parse(mockReader));
    }
}
